using System.ComponentModel.DataAnnotations;

namespace sv_3fac7750a3964e74be1bb0b651d13677.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    [Display(Name = "Product Name")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    [Display(Name = "Review Title")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    [Display(Name = "Review Body")]
    public string ReviewBody { get; set; } = string.Empty;
}

using sv_3fac7750a3964e74be1bb0b651d13677.Models;

namespace sv_3fac7750a3964e74be1bb0b651d13677.Services;

public class ReviewService
{
    /// <summary>
    /// Validates server-side business rules and submits the review.
    /// Returns a dictionary of field-specific errors (empty on success).
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(
        ReviewModel model, IReadOnlyList<PhotoInfo>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (model.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(model.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // Stub: add additional server-side rules here.

        return Task.FromResult(errors);
    }
}

public record PhotoInfo(string FileName, long SizeBytes);

@page "/write-review"
@rendermode InteractiveServer
@using sv_3fac7750a3964e74be1bb0b651d13677.Models
@using sv_3fac7750a3964e74be1bb0b651d13677.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h3>Write a Review</h3>

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        Your review has been submitted successfully. Thank you!
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleValidSubmit" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Product Name</label>
            <InputText class="form-control" @bind-Value="_model.ProductName" />
            <ValidationMessage For="() => _model.ProductName" />
            @if (_serverErrors.ContainsKey(nameof(_model.ProductName)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Rating</label>
            <InputNumber class="form-control" @bind-Value="_model.Rating" />
            <ValidationMessage For="() => _model.Rating" />
        </div>

        <div class="mb-3">
            <label class="form-label">Review Title</label>
            <InputText class="form-control" @bind-Value="_model.ReviewTitle" />
            <ValidationMessage For="() => _model.ReviewTitle" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewTitle)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Review Body</label>
            <InputTextArea class="form-control" rows="5" @bind-Value="_model.ReviewBody" />
            <ValidationMessage For="() => _model.ReviewBody" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewBody)))
            {
                <div class="validation-message">@_serverErrors[nameof(_model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile class="form-control" OnChange="OnPhotosSelected" multiple
                       accept=".jpg,.jpeg,.png" />
            @if (!string.IsNullOrEmpty(_photoError))
            {
                <div class="validation-message">@_photoError</div>
            }

            @if (_photos.Count > 0)
            {
                <ul class="list-group mt-2">
                    @foreach (var photo in _photos)
                    {
                        <li class="list-group-item d-flex justify-content-between align-items-center">
                            @photo.FileName
                            <span class="badge bg-secondary">@FormatSize(photo.SizeBytes)</span>
                        </li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
            @if (_isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
            }
            Submit Review
        </button>
    </EditForm>
}

@code {
    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFiles = 3;

    private ReviewModel _model = new();
    private List<PhotoInfo> _photos = new();
    private Dictionary<string, string> _serverErrors = new();
    private string? _photoError;
    private bool _submitted;
    private bool _isSubmitting;

    private void OnPhotosSelected(InputFileChangeEventArgs e)
    {
        _photoError = null;
        var files = e.GetMultipleFiles(MaxFiles + 1); // read one extra to detect overflow

        if (files.Count > MaxFiles)
        {
            _photoError = $"You can upload a maximum of {MaxFiles} photos.";
            return;
        }

        var accepted = new List<PhotoInfo>();
        foreach (var file in files)
        {
            if (file.Size > MaxFileSize)
            {
                _photoError = $""{file.Name}" exceeds the 5 MB limit.";
                return;
            }

            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (ext is not (".jpg" or ".jpeg" or ".png"))
            {
                _photoError = $""{file.Name}" is not a supported format. Only JPG and PNG are allowed.";
                return;
            }

            accepted.Add(new PhotoInfo(file.Name, file.Size));
        }

        _photos = accepted;
    }

    private async Task HandleValidSubmit()
    {
        _serverErrors.Clear();
        _isSubmitting = true;

        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(_model, _photos);

            if (errors.Count > 0)
            {
                _serverErrors = errors;
                return;
            }

            _submitted = true;
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F2} MB"
    };
}

