using sv_3fac7750a3964e74be1bb0b651d13677.Components;
using sv_3fac7750a3964e74be1bb0b651d13677.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddScoped<ReviewService>();

// Allow file uploads up to ~6 MB over the SignalR hub (default is 32 KB).
builder.Services.AddSignalR(options =>
{
    options.MaximumReceiveMessageSize = 6 * 1024 * 1024;
});

